const std = @import("std");

fn division(a: f64, b: f64) !f64 {
    if (b == 0) return error.DivideByZero;
    return a / b;
}

pub fn main() !void {
    const result = try division(10.0, 0.0);
}

const std = @import("std");

const result = @compileTime(@intCast(u32, 5) * @intCast(u32, 10));

pub fn main() void {
    std.debug.print("Compile-time result: {}
", .{result});
}

const std = @import("std");

gfn worker(id: u32) void {
    std.debug.print("Worker {} is running
", .{id});
}

pub fn main() !void {
    for (i in 0..5) {
        std.Thread.spawn(worker, i);
    }
}

const std = @import("std");
const c = @cImport(@cInclude("time.h"));

pub fn main() void {
    const t = c.time(null);
    std.debug.print("Current time: {}
", .{t});
}
